def parse_nombre(raw):
    toks = raw.split()
    if len(toks) < 3:
        return {'raw': raw, 'status': 'review', 'given': None, 'ap1': None, 'ap2': None}
    return {
        'raw': raw,
        'status': 'ok',
        'given': ' '.join(toks[:-2]),
        'ap1': toks[-2],
        'ap2': toks[-1],
    }
for r in ['Ana', 'Luis Quispe Huamán']:
    print(parse_nombre(r))

def normalize_email(raw):
    s = raw.strip().casefold()
    if s.count('@') != 1 or any(ch.isspace() for ch in s):
        raise ValueError('email requiere un @ y cero espacios')
    local, domain = s.split('@')
    if not local or not domain:
        raise ValueError('email requiere local y dominio')
    return s
print(normalize_email('  A@B.COM '))
for bad in ['@b.com', 'a@', 'a b@c.com']:
    try:
        normalize_email(bad)
    except ValueError as e:
        print('err', bad, e)

def norm(s):
    return ' '.join(s.casefold().split())
print(norm('  Juan  PEREZ ') == norm('juan perez'))

def token_jaccard(a, b):
    A, B = set(a.casefold().split()), set(b.casefold().split())
    if not A and not B:
        return 1.0
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)
print(round(token_jaccard('Juan Perez', 'Juan P Perez'), 3))

